import ast
import json

# Read the file
file_path = locals()['var_function-call-14256910595944161476']
with open(file_path, 'r') as f:
    businesses = json.load(f)

count = 0
debug_list = []

for b in businesses:
    attrs = b.get('attributes')
    # attrs can be None (null in json), "None" (string), or a dict.
    if not attrs or attrs == 'None':
        continue

    # Check BikeParking
    has_bike = False
    if 'BikeParking' in attrs:
        if attrs['BikeParking'] == 'True':
            has_bike = True

    # Check BusinessParking
    has_biz_parking = False
    if 'BusinessParking' in attrs:
        val = attrs['BusinessParking']
        if val == 'True':
            has_biz_parking = True
        elif val and val != 'None' and val != 'False':
            try:
                # Value is a string representation of a dict
                parking_dict = ast.literal_eval(val)
                if isinstance(parking_dict, dict):
                    # Check for garage, lot, valet, validated
                    # We exclude 'street' as it's usually public
                    # If any of these are True, then business offers parking
                    for key in ['garage', 'lot', 'valet', 'validated']:
                        if parking_dict.get(key) is True:
                            has_biz_parking = True
                            break
            except:
                pass

    if has_bike or has_biz_parking:
