import ast
import json

file_path = locals()['var_function-call-14256910595944161476']
with open(file_path, 'r') as f:
    businesses = json.load(f)

only_street_count = 0

for b in businesses:
    attrs = b.get('attributes')
    if not attrs or attrs == 'None':
        continue

    # Check BikeParking
    has_bike = False
    if 'BikeParking' in attrs and attrs['BikeParking'] == 'True':
        has_bike = True

    # Check BusinessParking
    has_private_parking = False
    has_street_only = False

    if 'BusinessParking' in attrs:
        val = attrs['BusinessParking']
        if val == 'True':
            has_private_parking = True # Assume True means yes
        elif val and val != 'None' and val != 'False':
            try:
                parking_dict = ast.literal_eval(val)
                if isinstance(parking_dict, dict):
                    # Check private
                    if any(parking_dict.get(k) is True for k in ['garage', 'lot', 'valet', 'validated']):
                        has_private_parking = True

                    # Check street
                    if parking_dict.get('street') is True:
                        # If street is true but no private parking
                        if not has_private_parking:
                            has_street_only = True
            except:
                pass

    # If it would be counted ONLY if we include street parking
    if not has_bike and not has_private_parking and has_street_only:
        only_street_count += 1

print("__RESULT__:")
print(only_street_count)

