                parking_dict = ast.literal_eval(val_str)
                if isinstance(parking_dict, dict):
                    # Check for garage, lot, valet, validated
                    # We EXCLUDE street
                    if any(parking_dict.get(k) is True for k in ['garage', 'lot', 'valet', 'validated']):
                        has_biz_parking = True
            except:
                pass

    if has_bike or has_biz_parking:
        count += 1

print("__RESULT__:")
